module RefModule (
    input wire [15:0] data_in,
    input wire we,
    input wire re,
    output reg [15:0] data_out
);
    reg [15:0] unused_storage;

    always @(posedge we) begin
        unused_storage <= data_in;
    end

    always @(posedge re) begin
        data_out <= unused_storage;
    end
endmodule
